x=[1 0 2 0 3 0 4 0 4 0 3 0 2 0 1];
nx=0:length(x)-1;

nh=-10:10;
h = sinc(0.5*n);

subplot(211);stem(nh,h);grid on;

subplot(212)
stem(nx,x,'r','linewidth',2);
axis([-2 16 -1 5]);hold on;

y=conv(x,h);
ny=[nx(1)+nh(1):nx(end)+nh(end)];

stem(ny,y)
axis([-2 16 -1 5]);grid on;
